  search: 'anthropic/claude-haiku-4.5',
  grade: 'anthropic/claude-sonnet-4',
  synthesize: 'anthropic/claude-opus-4',
  verify: 'openai/gpt-5', // independent family — catches anthropic blind spots
  cite: 'anthropic/claude-haiku-4.5',
};

/**
