export function routerPolicy(m: RoutingMatrix, label: string, pick: (q: string, m: RoutingMatrix) => string, prices = BLENDED_USD_PER_MTOK): PolicyResult {
  return evalPicks(m, label, (q) => pick(q, m), prices);
