const SECRET_RE = /(secret|token|key|password|passphrase)/i;

function sanitiseValue(v: unknown): unknown {
  if (v == null) return v;
  if (Array.isArray(v)) return v.map(sanitiseValue);
  if (typeof v === 'object') {
    const out: Record<string, unknown> = {};
