// emits the OTHER eight hosts' native config.

export interface HostConfigInput {
  name: string;
  description: string;
  /** Whether the harness ships an MCP surface (templates default to local). */
  mcp: 'off' | 'local' | 'remote';
  /** Default-deny posture knobs (ADR-022). */
