    }
    const counts = `${e.agentCount}a/${e.skillCount}s/${e.commandCount}c`;
    lines.push(`    ${e.id.padEnd(22)} ${counts.padEnd(10)} ${e.quickStart}`);
  }
  lines.push('', `Scaffold with: metaharness <name> --template <id>`);
  return lines;
}

