  description?: string;
  domain?: string;
  templateId?: string;
}

interface HarnessManifest {
  meta?: ManifestMeta;
  name?: string;
  description?: string;
  template?: string;
}

function manifestSummary(m: HarnessManifest): {
  name: string;
  description: string;
  templateId: string | undefined;
  domain: string | undefined;
} {
  // Tolerate both top-level fields (older manifests) and meta.* (newer).
  return {
    name: m.meta?.name ?? m.name ?? 'unnamed-harness',
    description: m.meta?.description ?? m.description ?? 'AI agent harness',
    templateId: m.meta?.templateId ?? m.template,
    domain: m.meta?.domain,
  };
}

function uniq<T>(arr: T[]): T[] { return [...new Set(arr)]; }

function buildPluginJson(s: ReturnType<typeof manifestSummary>): string {
  const cats = uniq(['agent-harness', 'metaharness-scaffold', ...(s.templateId?.startsWith('vertical:') ? ['vertical'] : []), ...(s.domain ? [s.domain] : [])]);
  const tags = uniq(['metaharness', 'agent-harness', ...(s.templateId ? [s.templateId] : []), ...(s.domain ? [s.domain] : [])]);
  return JSON.stringify({
    name: s.name,
    version: '0.1.0',
    description: s.description,
    author: {
      displayName: 'Generated by metaharness',
      url: 'https://www.npmjs.com/package/metaharness',
    },
    license: 'MIT',
    categories: cats,
    tags,
    homepage: 'https://github.com/ruvnet/agent-harness-generator',
  }, null, 2) + '\n';
}

