  // a persistent memory layer pays off more.
  const fileCount = Object.keys(files).length;
  const memoryUsefulness = clamp100(
    Math.min(fileCount, 30) * 2 + profile.languages.length * 5 + Math.min(profile.tokens.length, 25),
