  let s = 0;
  if (manifest) {
    s += 35;
    signals.push('manifest.json present');
    if (manifest.meta?.surface) {
      s += 20;
      signals.push(`surface=${manifest.meta.surface}`);
    }
    if (manifest.meta?.kernel_version) {
      s += 25;
