function scoreAgentUsefulness(dir: string): DimensionScore {
  const signals: string[] = [];
  let s = 0;
  const agents = countDir(dir, 'src/agents');
  const skills = countDir(dir, '.claude/skills');
  const commands = countDir(dir, '.claude/commands');
