  const scored = result.records
    .filter((r) => r.score)
    .sort((a, b) => (b.score?.finalScore ?? 0) - (a.score?.finalScore ?? 0));

  process.stdout.write('\nDarwin Mode — leaderboard\n');
  for (const r of scored.slice(0, 10)) {
