    process.stdout.write(
      `  ${s.finalScore.toFixed(3)}  ${r.variant.id}` +
        `  [${r.variant.mutationSurface}]  safety=${s.safetyScore.toFixed(2)}` +
        `  pass=${s.testPassRate.toFixed(2)}${tag}\n`,
    );
  }

