    const failed = t.exitCode !== 0 || t.timedOut || t.blockedActions.length > 0;
    if (!failed) continue;
    const why = t.blockedActions.length > 0
      ? `blocked: ${t.blockedActions.join(', ')}`
      : t.timedOut
