          max_tokens: this.maxTokens,
          temperature: this.temperature,
        }),
        signal: controller.signal,
      });
      clearTimeout(tid);
    } catch (e) {
      return { code: input.parentCode, summary: `ruvllm:${this.baseUrl} unreachable (${(e as Error).message}) — no-op` };
