/** Run ONE agent task against a variant by executing its real surface code. */
export async function runVariantTaskAgent(
  variant: HarnessVariant,
  task: AgentTask,
  timeoutMs = 10_000,
): Promise<RunTrace> {
  const scrubbedEnv: NodeJS.ProcessEnv = {
    PATH: process.env.PATH,
    METAHARNESS_VARIANT: variant.id,
    METAHARNESS_TASK: task.id,
  };
  let out: DriverOut = { solved: false, attemptsUsed: 0, durationMs: 0, log: '' };
  let blocked = false;
  try {
    const { stdout } = await execFileAsync(
      process.execPath,
      ['--experimental-strip-types', '--no-warnings', DRIVER, variant.dir, JSON.stringify(task)],
      { timeout: timeoutMs, env: scrubbedEnv, cwd: variant.dir, maxBuffer: 1 << 20 },
    );
    out = JSON.parse(stdout.trim() || '{}');
  } catch (e) {
    out = { solved: false, attemptsUsed: 0, durationMs: 0, log: `child error: ${(e as Error).message}`.slice(0, 200) };
    blocked = false; // a child failure is an unsolved task, not a safety block
  }
  const startedAt = '1970-01-01T00:00:00.000Z';
  return {
    variantId: variant.id,
    taskId: task.id,
    startedAt,
    finishedAt: new Date(out.durationMs).toISOString(),
    exitCode: out.solved ? 0 : 1,
    stdout: out.log,
    stderr: out.solved ? '' : `task ${task.id} unsolved (${out.attemptsUsed} attempts)`,
    durationMs: out.durationMs,
    timedOut: false,
    blockedActions: blocked ? ['tier2 child blocked'] : [],
  };
}

/** Run a variant against the agent suite (defaults to DEFAULT_AGENT_TASKS). */
export async function runVariantTasksAgent(
  variant: HarnessVariant,
  tasks: readonly AgentTask[] = DEFAULT_AGENT_TASKS,
  timeoutMs = 10_000,
): Promise<RunTrace[]> {
  const traces: RunTrace[] = [];
  for (const task of tasks) traces.push(await runVariantTaskAgent(variant, task, timeoutMs));
  return traces;
}

