export interface AgentSpec {
  /** Stable worker id, e.g. "coder", "reviewer". */
  id: string;
  /** Model label recorded on receipts, e.g. "haiku". */
  model: string;
  /** The kinds of plan step this worker can handle. */
  handles: string[];
  /** The worker implementation. */
  run: Worker;
}

