      id: top.candidateId,
      confidence: top.confidence,
      uncertainty: top.uncertainty,
      useLightweight: top.useLightweight,
      ...(priceOf(top.candidateId) != null ? { costPerMTok: priceOf(top.candidateId) } : {}),
      inferenceTimeUs: res.inferenceTimeUs,
    };
  }

